# .github/workflows/eval.yml — using the eval platform (from catalog entry)
- name: Run evals via platform
  run: |
    curl -X POST https://eval-platform.internal/api/v1/runs       -H "Authorization: Bearer $EVAL_PLATFORM_TOKEN"       -H "Content-Type: application/json"       -d '{
        "suite_id": "my-service-evals",
        "service_version": "${{ github.sha }}",
        "threshold": {"pass_rate": 0.95}
      }'
